begin;
alter table public.leads add column if not exists email_normalized text,add column if not exists source_normalized text,add column if not exists identity_key text,add column if not exists canonical_contract_version integer not null default 1,add column if not exists data_quality_percent integer not null default 0 check(data_quality_percent between 0 and 100),add column if not exists data_quality_status text not null default 'critical' check(data_quality_status in('critical','incomplete','usable','complete')),add column if not exists data_quality_issues text[] not null default '{}',add column if not exists quality_calculated_at timestamptz;
create index if not exists leads_org_email_normalized_idx on public.leads(organization_id,email_normalized)where email_normalized is not null;create index if not exists leads_org_identity_key_idx on public.leads(organization_id,identity_key)where identity_key is not null;create index if not exists leads_quality_idx on public.leads(organization_id,data_quality_status,data_quality_percent,updated_at desc);
create table if not exists public.lead_data_quality_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,previous_percent integer,new_percent integer not null,issues text[] not null,contract_version integer not null,source text not null check(source in('write_trigger','portfolio_refresh')),created_at timestamptz not null default now());alter table public.lead_data_quality_events enable row level security;drop policy if exists lead_data_quality_events_scope on public.lead_data_quality_events;create policy lead_data_quality_events_scope on public.lead_data_quality_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.lead_data_quality_events from anon;revoke insert,update,delete on public.lead_data_quality_events from authenticated;grant select on public.lead_data_quality_events to authenticated;
create or replace function private.apply_canonical_lead_contract()returns trigger language plpgsql security definer set search_path='' as $$declare score integer:=0;issues text[]:='{}';digits text;begin new.email_normalized:=nullif(lower(trim(coalesce(new.email,''))),'');digits:=regexp_replace(coalesce(new.phone,''),'\D','','g');if length(digits)in(10,11)then digits:='55'||digits;end if;new.phone_normalized:=case when length(digits)between 10 and 15 then digits else null end;new.source_normalized:=nullif(lower(trim(coalesce(new.source,''))),'');new.identity_key:=case when new.phone_normalized is not null then'phone:'||new.phone_normalized when new.email_normalized is not null then'email:'||new.email_normalized else null end;new.canonical_contract_version:=1;if length(trim(coalesce(new.name,'')))>=2 then score:=score+10;else issues:=issues||'name';end if;if new.phone_normalized is not null or new.email_normalized is not null then score:=score+15;else issues:=issues||'contact';end if;if new.source_normalized is not null then score:=score+10;else issues:=issues||'source';end if;if new.purpose is not null then score:=score+10;else issues:=issues||'purpose';end if;if new.budget_min is not null or new.budget_max is not null then score:=score+10;else issues:=issues||'budget';end if;if coalesce(array_length(new.preferred_regions,1),0)>0 then score:=score+10;else issues:=issues||'regions';end if;if new.bedrooms is not null then score:=score+5;else issues:=issues||'bedrooms';end if;if new.development_id is not null then score:=score+10;else issues:=issues||'development';end if;if new.next_action_at is not null then score:=score+10;else issues:=issues||'next_action';end if;if coalesce(new.metadata,'{}'::jsonb)?'qualification' or coalesce(length(trim(new.notes)),0)>10 then score:=score+10;else issues:=issues||'commercial_context';end if;new.data_quality_percent:=score;new.data_quality_status:=case when score>=90 then'complete'when score>=70 then'usable'when score>=40 then'incomplete'else'critical'end;new.data_quality_issues:=issues;new.quality_calculated_at:=now();return new;end $$;
drop trigger if exists normalize_lead_phone_before_write on public.leads;drop trigger if exists apply_canonical_lead_contract_before_write on public.leads;create trigger apply_canonical_lead_contract_before_write before insert or update of name,email,phone,source,purpose,budget_min,budget_max,preferred_regions,bedrooms,development_id,next_action_at,metadata,notes on public.leads for each row execute function private.apply_canonical_lead_contract();
create or replace function public.refresh_canonical_lead_quality(p_actor_id uuid,p_organization_id uuid)returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;item public.leads;previous integer;changed integer:=0;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent','manager')then raise exception 'lead_quality_actor_forbidden';end if;for item in select * from public.leads where organization_id=p_organization_id for update loop previous:=item.data_quality_percent;update public.leads set name=item.name where id=item.id returning * into item;if previous is distinct from item.data_quality_percent then insert into public.lead_data_quality_events(organization_id,lead_id,previous_percent,new_percent,issues,contract_version,source)values(p_organization_id,item.id,previous,item.data_quality_percent,item.data_quality_issues,item.canonical_contract_version,'portfolio_refresh');changed:=changed+1;end if;end loop;return jsonb_build_object('organizationId',p_organization_id,'changed',changed,'contractVersion',1,'deterministic',true,'llmCost',0,'personalDataExposed',false);end $$;
revoke all on function public.refresh_canonical_lead_quality(uuid,uuid)from public,anon,authenticated;grant execute on function public.refresh_canonical_lead_quality(uuid,uuid)to service_role;
update public.leads set name=name;
commit;
